ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?articles a :Articles .
    ?photos a :photos .
    ?photos p:hasarticles ?articles .
    ?photos p:photo ?photo .
    BIND(?photo AS ?o0)
  }
  UNION
  {
    ?articles a :Articles .
    ?videos a :videos .
    ?videos p:hasarticles ?articles .
    ?videos p:video ?video .
    ?articles p:content ?content_f .
    FILTER(STR(?content_f) = "A look at the growing popularity of electric cars and their implications for the automotive industry...")
    BIND(?video AS ?o0)
  }
} }
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?articles a :Articles .
    ?photos a :photos .
    ?photos p:hasarticles ?articles .
    ?photos p:photo ?photo .
    ?articles p:content ?content_f .
    FILTER(STR(?content_f) = "A look at the growing popularity of electric cars and their implications for the automotive industry...")
    BIND(?photo AS ?o0)
  }
  UNION
  {
    ?articles a :Articles .
    ?videos a :videos .
    ?videos p:hasarticles ?articles .
    ?videos p:video ?video .
    ?articles p:content ?content_f .
    FILTER(STR(?content_f) = "A look at the growing popularity of electric cars and their implications for the automotive industry...")
    BIND(?video AS ?o0)
  }
} }
}
